sql:
SELECT request_id, status, request_time 
FROM resource_requests 
WHERE status = 'approved';

SELECT COUNT(*) 
FROM resource_requests 
WHERE user_id = 1 AND status = 'approved';

SELECT node_id, AVG(time_to_resource_seconds) AS avg_time_to_resource
FROM resource_allocations
GROUP BY node_id;

SELECT resource_id, status, status_time 
FROM resource_status_history 
WHERE DATETIME(status_time) > DATETIME('now', '-1 week');

